package pe.org.camaracomercioica.protestos.controller; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import pe.org.camaracomercioica.protestos.dto.*; import pe.org.camaracomercioica.protestos.service.CatalogoService; import java.util.List; @RestController @RequestMapping("/api/analistas") @RequiredArgsConstructor public class AnalistaController {private final CatalogoService service;@GetMapping List<AnalistaResponse> listar(){return service.analistas();}@PostMapping @ResponseStatus(HttpStatus.CREATED) AnalistaResponse crear(@Valid @RequestBody AnalistaRequest r){return service.crear(r);}}
